import React from 'react';

const Button = ({ children, variant = 'primary', className = '', ...props }) => {
    const baseStyle = "px-6 py-2.5 rounded-md font-medium transition-all duration-200 flex items-center justify-center gap-2";

    // Hand-rolled styles mapping to our global.css variables and design system
    const variants = {
        primary: "bg-teal-500 hover:bg-teal-600 text-white shadow-glow",
        secondary: "bg-amber-500 hover:bg-amber-600 text-white shadow-glow-gold",
        outline: "border border-white/20 hover:border-teal-500 hover:text-teal-400 text-white/80 bg-transparent",
        ghost: "bg-transparent hover:bg-white/5 text-white/70 hover:text-white"
    };

    // Inline fallback if standard Tailwind isn't enabled (which we didn't install Tailwind directly, we are using Vanilla CSS mapping)
    // Wait, the user didn't want Tailwind unless requested. I'm using vanilla CSS!

    // Let's use standard classes and define them in global.css if needed, or inline styles
    const getStyle = () => {
        switch (variant) {
            case 'primary': return { background: 'var(--primary)', color: '#fff', border: 'none' };
            case 'secondary': return { background: 'var(--secondary)', color: '#fff', border: 'none' };
            case 'outline': return { background: 'transparent', border: '1px solid var(--border-light)', color: 'var(--text-main)' };
            case 'ghost': return { background: 'transparent', border: 'none', color: 'var(--text-muted)' };
            default: return {};
        }
    };

    return (
        <button
            className={`btn ${variant} ${className}`}
            style={{
                padding: '0.6rem 1.2rem',
                borderRadius: 'var(--radius-sm)',
                fontFamily: 'var(--font-sans)',
                fontWeight: '500',
                cursor: 'pointer',
                transition: 'all 0.2s',
                display: 'inline-flex',
                alignItems: 'center',
                gap: '0.5rem',
                ...getStyle()
            }}
            {...props}
        >
            {children}
        </button>
    );
};

export default Button;

import { createContext, useState, useContext } from 'react';

const AuthContext = createContext();

export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);

    const login = (email, password) => {
        // Mock login logic
        if (email === 'admin@hostel.edu' && password === 'admin123') {
            setUser({ role: 'admin', name: 'Hostel Admin', email });
            return true;
        } else if (email === 'student@college.edu' && password === 'student123') {
            setUser({ role: 'student', id: 1, name: 'Mahesh', email, room: 'A-101', cgpa: 8.9 });
            return true;
        }
        return false;
    };

    const logout = () => {
        setUser(null);
    };

    return (
        <AuthContext.Provider value={{ user, login, logout }}>
            {children}
        </AuthContext.Provider>
    );
};

import { createContext, useState, useContext } from 'react';
import { mockStudents, mockRooms, mockComplaints, mockNotices, messMenuData } from '../data/mockData';

const HostelContext = createContext();

export const useHostel = () => useContext(HostelContext);

export const HostelProvider = ({ children }) => {
    const [students, setStudents] = useState(mockStudents);
    const [rooms, setRooms] = useState(mockRooms);
    const [complaints, setComplaints] = useState(mockComplaints);
    const [notices, setNotices] = useState(mockNotices);
    const [messMenu] = useState(messMenuData);

    const addComplaint = (newComplaint) => {
        setComplaints([{ id: Date.now(), ...newComplaint, status: 'Pending', date: new Date().toISOString().split('T')[0] }, ...complaints]);
    };

    const resolveComplaint = (id, reply) => {
        setComplaints(complaints.map(c => c.id === id ? { ...c, status: 'Resolved', reply } : c));
    };

    const allocateRoom = (studentId, roomId) => {
        setStudents(students.map(s => s.id === studentId ? { ...s, room: roomId } : s));
        setRooms(rooms.map(r => r.id === roomId ? { ...r, occupants: r.occupants + 1 } : r));
    };

    const addNotice = (notice) => {
        setNotices([{ id: Date.now(), ...notice, date: new Date().toISOString().split('T')[0] }, ...notices]);
    };

    return (
        <HostelContext.Provider value={{
            students, rooms, complaints, notices, messMenu,
            addComplaint, resolveComplaint, allocateRoom, addNotice, setStudents
        }}>
            {children}
        </HostelContext.Provider>
    );
};
